class Solution:
    def canMakePalindromeQueries(self, s: str, queries: List[List[int]]) -> List[bool]:
        n = len(s)
        half = n // 2
        from collections import Counter

        # Precompute prefix sums for each character
        prefix = [Counter() for _ in range(n + 1)]
        for i in range(n):
            prefix[i + 1] = prefix[i].copy()
            prefix[i + 1][s[i]] += 1

        def get_count(l, r, ch):
            return prefix[r + 1][ch] - prefix[l][ch]

        answer = []
        for a, b, c, d in queries:
            # Count characters in the first half and second half
            left = Counter()
            for i in range(half):
                left[s[i]] += 1

            right = Counter()
            for i in range(half, n):
                right[s[i]] += 1

            # Get the characters in the ranges we can rearrange
            left_range = Counter()
            for i in range(a, b + 1):
                left_range[s[i]] += 1

            right_range = Counter()
            for i in range(c, d + 1):
                right_range[s[i]] += 1

            # Subtract the ranges from the left and right
            for ch in left_range:
                left[ch] -= left_range[ch]
                if left[ch] == 0:
                    del left[ch]

            for ch in right_range:
                right[ch] -= right_range[ch]
                if right[ch] == 0:
                    del right[ch]

            # Check if left and right can be made equal
            if left == right:
                answer.append(True)
            else:
                answer.append(False)

        return answer
